#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long S; scanf("%lld", &S);
        long long ans = -(S + 1);
        printf("%lld\n", ans);
    }
    return 0;
}

